import{_ as t,o as a,c as o,ae as s}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Webhooks for Developers","description":"","frontmatter":{"title":"Webhooks for Developers","slug":"data-integration-webhooks-for-developers"},"headers":[],"relativePath":"developer-hub/data-integration-webhooks-for-developers.md","filePath":"developer-hub/data-integration-webhooks-for-developers.md"}'),n={name:"developer-hub/data-integration-webhooks-for-developers.md"};function i(r,e,l,p,u,d){return a(),o("div",null,[...e[0]||(e[0]=[s(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch&#39;s webhook system allows you to export install and down-funnel event data as it occurs. You can import this data into your internal systems for analysis. You simply need to specify a URL for the POST or GET requests.</p><p>If you are looking for postback integrations for ad networks, please visit our <a href="./ads-overview.html">Ads documentation</a>. For pre-configured integrations into popular analytics tools, please visit our <a href="./data-integration-implementation-guide.html">Data Integrations documentation</a>.</p><p>The webhook system is highly customizable. You can register to only receive notifications for specific events, as well as specific subsections of events, filtered by link data, user data or event properties.</p><p>Our webhook infrastructure supports all Branch events. The data is formatted according to standard event naming and metadata format which will get you through implementation and on to analysis in no time.</p><h2 id="data-format" tabindex="-1">Data format <a class="header-anchor" href="#data-format" aria-label="Permalink to &quot;Data format&quot;">​</a></h2><p>Setting up Advanced Filters or Freemarker macros requires an understanding of the Event Ontology data format. Before diving into the schema, you should understand some high level concepts about event metadata structure:</p><ul><li>Each event has top level fields, such as &quot;name&quot; and &quot;id&quot; that are not nested</li><li>Link data is generally nested in &quot;Last Attributed Touch Data&quot;</li><li>User data (including device and OS data) is nested in &quot;User Data&quot;</li><li>Product or content level data is nested in &quot;Content Items&quot;</li><li>Transaction and generic content data is nested in &quot;Event Data&quot;</li><li>Journeys or Deepviews view data (e.g. Journey banners loads, not clicks) is &quot;Last CTA View Data&quot;</li><li>Client-specified custom data (e.g. internal fields your company requires on specific events) is nested in &quot;Custom Data&quot;</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>To find a complete list of Branch supported postback macros, please see <a href="./postback-macros-functions.html">Postback Macros &amp; Functions</a>.</p></div><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Geographic data, such as country and city, may not be available for a very small percentage of events where the IP cannot be resolved to a location.</p></div><h3 id="sample-webhook-post-body-syntax" tabindex="-1">Sample webhook POST body syntax <a class="header-anchor" href="#sample-webhook-post-body-syntax" aria-label="Permalink to &quot;Sample webhook POST body syntax&quot;">​</a></h3><p>The POST body for all webhooks follows the same structure:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST</span></span>
<span class="line"><span>        User-agent: Branch Metrics API</span></span>
<span class="line"><span>        Content-Type: application/json</span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>        &quot;name&quot;: &quot;&lt;event name e.g. open&gt;&quot;,</span></span>
<span class="line"><span>        &quot;user_data&quot;: {},</span></span>
<span class="line"><span>        &quot;last_cta_view_data&quot;: {},</span></span>
<span class="line"><span>        &quot;last_attributed_touch_data&quot;: {},</span></span>
<span class="line"><span>        &quot;custom_data&quot;: {},</span></span>
<span class="line"><span>        &quot;event_data&quot;: {},</span></span>
<span class="line"><span>        &quot;content_items&quot;: {},</span></span>
<span class="line"><span>        &quot;timestamp&quot;: &#39;example timestamp (int)&#39;</span></span>
<span class="line"><span>        }</span></span></code></pre></div><p>If any of these objects are empty, they will not appear in the POST body.</p><p>Here&#39;s a POST body with example data for an attributed open:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Attributed open</span></span>
<span class="line"><span>        POST</span></span>
<span class="line"><span>        User-agent: Branch Metrics API</span></span>
<span class="line"><span>        Content-Type: application/json</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        {</span></span>
<span class="line"><span>        &quot;name&quot;: &quot;open&quot;,</span></span>
<span class="line"><span>        &quot;user_data&quot;: {</span></span>
<span class="line"><span>        &quot;os&quot;: &quot;IOS&quot;,</span></span>
<span class="line"><span>        &quot;os_version&quot;: &quot;11.1.2&quot;,</span></span>
<span class="line"><span>        &quot;environment&quot;: &quot;FULL_APP&quot;,</span></span>
<span class="line"><span>        &quot;platform&quot;: &quot;IOS_APP&quot;,</span></span>
<span class="line"><span>        &quot;idfa&quot;: &quot;F520B35A-4165-4426-98F6-64F12F47E9BZ&quot;,</span></span>
<span class="line"><span>        &quot;idfv&quot;: &quot;C6B869E7-7B0A-4A93-1C3D-960E8859DP5D&quot;,</span></span>
<span class="line"><span>        &quot;limit_ad_tracking&quot;: false,</span></span>
<span class="line"><span>        &quot;user_agent&quot;: &quot;Mozilla/5.0 (iPhone; CPU iPhone OS 11_1_2 like Mac OS X) AppleWebKit/604.3.5 (KHTML, like Gecko) Mobile/15B202&quot;,</span></span>
<span class="line"><span>        &quot;ip&quot;: &quot;50.200.105.218&quot;,</span></span>
<span class="line"><span>        &quot;developer_identity&quot;: &quot;DB8C86A6-8B7C-4192-BD29-8107A5B788A1&quot;,</span></span>
<span class="line"><span>        &quot;country&quot;: &quot;US&quot;,</span></span>
<span class="line"><span>        &quot;language&quot;: &quot;EN&quot;,</span></span>
<span class="line"><span>        &quot;brand&quot;: &quot;Apple&quot;</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>        &quot;last_cta_view_data&quot;: {</span></span>
<span class="line"><span>        &quot;~id&quot;: 457624031399716729,</span></span>
<span class="line"><span>        &quot;~campaign&quot;: &quot;_test&quot;,</span></span>
<span class="line"><span>        &quot;~feature&quot;: &quot;journeys&quot;,</span></span>
<span class="line"><span>        &quot;+domain&quot;: &quot;branchster.app.link&quot;,</span></span>
<span class="line"><span>        &quot;+url&quot;: &quot;https://branchster.app.link/jeMczRn5XH&quot;,</span></span>
<span class="line"><span>        &quot;$deeplink_path&quot;: &quot;open/item/1234&quot;,</span></span>
<span class="line"><span>        &quot;~creation_source&quot;: 5,</span></span>
<span class="line"><span>        &quot;+referrer&quot;: &quot;https://store.com/products/green-table&quot;,</span></span>
<span class="line"><span>        &quot;foo&quot;: &quot;bar&quot;,</span></span>
<span class="line"><span>        &quot;$canonical_url&quot;: &quot;https://store.com/products/green-table&quot;,</span></span>
<span class="line"><span>        &quot;mydata&quot;: &quot;set_branch_view_data_value&quot;,</span></span>
<span class="line"><span>        &quot;~tags&quot;: [</span></span>
<span class="line"><span>        &quot;tag1&quot;,</span></span>
<span class="line"><span>        &quot;tag2&quot;,</span></span>
<span class="line"><span>        &quot;bottom_banner_style&quot;</span></span>
<span class="line"><span>        ]</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>        &quot;last_attributed_touch_data&quot;: {</span></span>
<span class="line"><span>        &quot;~id&quot;: 467391383381228204,</span></span>
<span class="line"><span>        &quot;~feature&quot;: &quot;marketing&quot;,</span></span>
<span class="line"><span>        &quot;~campaign&quot;: &quot;december_test&quot;,</span></span>
<span class="line"><span>        &quot;~channel&quot;: &quot;Facebook Organic&quot;,</span></span>
<span class="line"><span>        &quot;product_id&quot;: &quot;XBA8198j&quot;,</span></span>
<span class="line"><span>        &quot;product_name&quot;: &quot;Green Table AB10&quot;,</span></span>
<span class="line"><span>        &quot;+url&quot;: &quot;https://branchster.app.link/test_linking&quot;,</span></span>
<span class="line"><span>        &quot;$marketing_title&quot;: &quot;Deep Link Testing&quot;,</span></span>
<span class="line"><span>        &quot;$ios_deepview&quot;: &quot;branch_default&quot;,</span></span>
<span class="line"><span>        &quot;+via_features&quot;: [</span></span>
<span class="line"><span>        &quot;QUICK_LINKS&quot;</span></span>
<span class="line"><span>        ]</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>        &quot;custom_data&quot;: {</span></span>
<span class="line"><span>        &quot;reinstall&quot;: &quot;false&quot;,</span></span>
<span class="line"><span>        &quot;ip&quot;: &quot;50.200.105.218&quot;,</span></span>
<span class="line"><span>        &quot;referred&quot;: &quot;false&quot;</span></span>
<span class="line"><span>        },</span></span>
<span class="line"><span>        &quot;timestamp&quot;: 1512681005807</span></span>
<span class="line"><span>        }</span></span></code></pre></div><h3 id="advanced-filtering" tabindex="-1">Advanced filtering <a class="header-anchor" href="#advanced-filtering" aria-label="Permalink to &quot;Advanced filtering&quot;">​</a></h3><p>Branch supports advanced filtering which allows you to set filters based on almost any event metadata.</p><p>Make sure you&#39;ve taken a look at the data format before you attempt to set advanced filters.</p><p>Complete the following steps to create an advanced filter:</p><ol><li>Select the <strong>Add New Filter</strong> button.</li><li>Select the metadata you&#39;d like to filter on. For advanced filtering, choose &quot;Custom.&quot;</li><li>Type in the key that you&#39;d like to filter on. To find the key you&#39;d like to filter on, reference our quick introduction to the Br data format to figure out where your key is likely nested. Another foolproof way to find your key is looking at your data in full before setting up your filter. You can do this by doing a <a href="https://dashboard.branch.io/data-import-export/csv-exports" target="_blank" rel="noreferrer">CSV export</a>, <a href="https://help.branch.io/" target="_blank" rel="noreferrer">API export</a>, or send a single webhook with a POST body. You can locate your key in that POST body.</li><li>Unless your key is part of the top level data (e.g. <strong>timestamp</strong> or <strong>id</strong>), it will likely be nested one level deep. Most keys will be of the format <strong>object_name.key</strong>. For example, if you want to filter for a custom key in deep link data called &quot;product_deeplink_id&quot;, that would take the form <strong>last_attributed_touch_data.product_deeplink_id</strong>.</li></ol><h4 id="advanced-filtering-example" tabindex="-1">Advanced filtering example <a class="header-anchor" href="#advanced-filtering-example" aria-label="Permalink to &quot;Advanced filtering example&quot;">​</a></h4><p>Let&#39;s say you&#39;re interested in receiving a webhook for every <strong>Purchase</strong> event using a specific coupon. When you set up the Purchase event in your app or on your website, you added a specific piece of metadata for <strong>coupon</strong>. In the <a href="./branch-event-ontology.html">Event Ontology Schema</a> you saw that coupon is inside event_data.</p><p>To configure your filter to fire a webhook only when coupon is equal to SUMMERDEALS10 you will:</p><ol><li>Select <strong>Custom</strong> from the <strong>Field Name</strong> dropdown.</li><li>Set the key as <strong>event_data.coupon.</strong></li><li>Select <strong>equals</strong> on the <strong>Comparator</strong> drop-down.</li><li>Enter a value of <strong>SUMMERDEALS10.</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Currently, webhooks do not support filtering on values inside arrays. Example arrays that cannot be filtered by value are <strong>tags</strong>, <strong>+via_features</strong>, and <strong>content_items</strong>.</p></div><h3 id="templating-your-postback-url" tabindex="-1">Templating your postback URL <a class="header-anchor" href="#templating-your-postback-url" aria-label="Permalink to &quot;Templating your postback URL&quot;">​</a></h3><p>If you&#39;d like to template your postback URL, you&#39;ll likely need to create one of our templated postback URLs along side the aforementioned filters. These work very similarly to filters but use Freemarker syntax.</p><h4 id="getting-started-with-templates" tabindex="-1">Getting started with templates <a class="header-anchor" href="#getting-started-with-templates" aria-label="Permalink to &quot;Getting started with templates&quot;">​</a></h4><p>To start, we can add a simple template. Let&#39;s say we want to add campaign as a query parameter. The correct syntax is</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>\`https://webhook.com?campaign=\${(last_attributed_touch_data.~campaign)!}\`</span></span></code></pre></div><p>Let&#39;s walk through the syntax:</p><ol><li>First, find the key for the value you want to template in. As with filtering, to find the key, reference our quick introduction to the Branch data format to figure out where your key is likely nested. Another foolproof way to find your key is looking at your data in full before setting up your filter. You can do this by doing a <a href="https://dashboard.branch.io/data-import-export/csv-exports" target="_blank" rel="noreferrer">CSV export</a>, API export or send a single webhook with a POST body, and locate your key in that POST body.</li><li>This exercise tells us that Campaign is nested inside <code>last_attributed_touch_data</code> and is represented by <code>last_attributed_touch_data.~campaign</code>.</li><li>The additional syntax around <code>last_attributed_touch_data.~campaign</code> is because Branch&#39;s templating engine uses Freemarker. In Freemarker, you can print variables by surrounding them with <code>\${}</code>. Finally, we add <code>()!</code> to the variable because we want to prevent errors in the case that there is no value.</li><li>This leaves us with <code>\${(last_attributed_touch_data.~campaign)!}</code>.</li></ol><p>Here is some more example Freemarker for common templates:</p><table tabindex="0"><thead><tr><th>Parent object</th><th>Common name</th><th>Freemarker</th></tr></thead><tbody><tr><td>Bundle</td><td>Android Package Name</td><td><code>\${(bundle.android.package_name)!}</code></td></tr><tr><td>Bundle</td><td>iOS Bundle ID</td><td><code>\${(bundle.ios.bundle_id)!}</code></td></tr><tr><td>Last Attributed Touch Data</td><td>Feature</td><td><code>\${(last_attributed_touch_data.~feature)!}</code></td></tr><tr><td>Last Attributed Touch Data</td><td>Channel</td><td><code>\${(last_attributed_touch_data.~channel)!}</code></td></tr><tr><td>Last Attributed Touch Data</td><td>Campaign</td><td><code>\${(last_attributed_touch_data.~campaign)!}</code></td></tr><tr><td>Last Attributed Touch Data</td><td>Ad Partner Name</td><td><code>\${(last_attributed_touch_data.~advertising_partner_name)!}</code></td></tr><tr><td>User Data</td><td>OS</td><td><code>\${(user_data.os)!}</code></td></tr><tr><td>User Data</td><td>Platform</td><td><code>\${(user_data.platform)!}</code></td></tr><tr><td>User Data</td><td>IDFA</td><td><code>\${(user_data.idfa)!}</code></td></tr><tr><td>User Data</td><td>IDFV</td><td><code>\${(user_data.idfv)!}</code></td></tr><tr><td>User Data</td><td>Android Advertising ID</td><td><code>\${(user_data.aaid)!}</code></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Note</p><p>To find a complete list of Branch supported postback macros, please see <a href="./branch-event-ontology.html">Postback Macros &amp; Functions</a>.</p></div><h4 id="freemarker-expressions" tabindex="-1">Freemarker expressions <a class="header-anchor" href="#freemarker-expressions" aria-label="Permalink to &quot;Freemarker expressions&quot;">​</a></h4><p>Due to security restrictions, Branch does not support the full list of Freemarker expressions.</p><p>Here is a list of blocked expressions:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;&lt;#import&gt;&quot;, &quot;&lt;#visit&gt;&quot;, &quot;&lt;#include&gt;&quot;, &quot;?eval&quot;, &quot;&lt;#recurse&gt;&quot;, &quot;&lt;#setting&gt;&quot;, &quot;&lt;#macro&gt;&quot;, &quot;&lt;#function&gt;&quot;, &quot;&lt;#nested&gt;&quot;, &quot;&lt;#return&gt;&quot;, &quot;&lt;#list&gt;&quot;</span></span></code></pre></div><h2 id="allowlist-webhook-ip-addresses" tabindex="-1">Allowlist webhook IP addresses <a class="header-anchor" href="#allowlist-webhook-ip-addresses" aria-label="Permalink to &quot;Allowlist webhook IP addresses&quot;">​</a></h2><p>If required by your setup, allowlist the following postback server IP addresses for security purposes:</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>- 52.43.119.253/32 - 100.21.145.61/32 - 35.160.5.60/32 - 35.163.128.27/32 - 54.241.169.87/32 - 44.229.177.148/32 - 35.167.148.222/32 - 44.231.103.124/32 - 44.237.121.167/32 - 44.238.95.201/32 - 52.52.236.153/32</td><td>- 44.247.175.42/32 - 44.247.58.38/32 - 52.33.75.0/32 - 52.34.127.49/32 - 54.177.16.103/32 - 54.213.17.93/32 - 184.169.196.16/32 - 35.161.135.86/32 - 44.230.175.24/32 - 52.27.172.117/32 - 35.160.133.187/32</td></tr></tbody></table><h3 id="optional-configure-aws-security-group" tabindex="-1">Optional: Configure AWS security group <a class="header-anchor" href="#optional-configure-aws-security-group" aria-label="Permalink to &quot;Optional: Configure AWS security group&quot;">​</a></h3><p>If you have an AWS account you use for webhooks, you will need to create a security group, as well as a series of inbound rules associated with that security group.</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>This example <strong>does not include the entire list</strong> of IP addresses you need to make rules for. Find those <a href="./webhooks-for-developers.html#allowlist-webhook-ip-addresses">above</a>.</p></div></div><p>:::</p><h3 id="optional-configure-gcp-firewall-policy" tabindex="-1">Optional: Configure GCP firewall policy <a class="header-anchor" href="#optional-configure-gcp-firewall-policy" aria-label="Permalink to &quot;Optional: Configure GCP firewall policy&quot;">​</a></h3><p><strong>If you have an GCP account</strong> you use for webhooks, you will need to create a firewall policy, as well as a series of firewall rules associated with that policy.</p><p>This example <strong>does not include the entire list</strong> of IP addresses you need to make rules for. Find those <a href="./webhooks-for-developers.html#allowlist-webhook-ip-addresses">above</a>.</p><h3 id="authenticating-webhook-events" tabindex="-1">Authenticating webhook events <a class="header-anchor" href="#authenticating-webhook-events" aria-label="Permalink to &quot;Authenticating webhook events&quot;">​</a></h3><p>Use the <strong>Filters</strong> tab to configure your own headers and authenticate your webhook events.</p><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><h4 id="liveview" tabindex="-1">Liveview <a class="header-anchor" href="#liveview" aria-label="Permalink to &quot;Liveview&quot;">​</a></h4><p>Use Branch’s <a href="./liveview.html">Liveview</a> feature to monitor your webhook records as they fire. You can see the complete request and response data for each webhook, including status codes that show whether your webhooks are successfully delivering (200) or encountering errors (400/500). Use the advanced filtering options to quickly pinpoint specific webhooks and troubleshoot any issues with your data integrations.</p><h4 id="requestbin" tabindex="-1">RequestBin <a class="header-anchor" href="#requestbin" aria-label="Permalink to &quot;RequestBin&quot;">​</a></h4><p>To test whether your webhook is configured correctly, you can use <a href="https://requestbin.com/" target="_blank" rel="noreferrer">RequestBin</a>. RequestBin gives you a URL that accepts events for 24 hours and allows you to see exactly what Branch is sending.</p><ol><li>Go to <a href="https://requestbin.com/" target="_blank" rel="noreferrer">RequestBin</a> and select <strong>+ Create Request Bin</strong>.</li><li>Copy the <strong>Endpoint URL</strong>.</li><li>Create a new webhook and use the <strong>Endpoint URL</strong> as your webhook URL.</li><li>Whenever your webhook is triggered, you will see a full report on RequestBin:</li></ol><div class="warning custom-block"><p class="custom-block-title">Warning</p><p>Please archive your Requestbin webhook when you have finished testing. Requestbins only last for 24 hours and return errors once they expire.</p></div><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>For more information on webhook configuration and testing, visit our <a href="./webhooks.html">marketer documentation</a>.</p><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>What is the retry logic for webhooks?</summary><p>We will retry if it&#39;s a timeout which can be on our end or our partner&#39;s end.</p><ul><li>Error codes mean it succeeded from our end and the recipient responded with an error, and we don&#39;t retry those.</li><li>Since most partners&#39; errors are caused by misconfigured webhooks and it would create a no-value load on our system.</li></ul><p>In addition, the 500 timeout error definition is based on our setting, not based on their system, we are waiting only 2 seconds and if they did not respond back within 2 seconds we will log 500 with the timeout error message.<br> It is possible that they could receive data even though there is a 500 response code with a timeout error in our postback logs. When we have a waiting time (2 seconds) less than what their server took to process the request then we could see a timeout error at our end.</p><p><strong>Note</strong>: <code>webhook_response_time_ms</code> in the raw data is not the time between request and response. This returns a time from postback request creation to webhooks record logging.</p></details>`,63)])])}const q=t(n,[["render",i]]);export{h as __pageData,q as default};
